local auth_token = ngx.var.http_authorization
if not auth_token then
    return ngx.exit(401)
end
auth_token = string.gsub(auth_token, "Basic ", "")
local user, pass = ngx.decode_base64(auth_token)
if not user or not pass then
    return ngx.exit(403)
